* {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background-color: #fafafa;
}

.aanpassingen-layout {
    width: 100%;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    background-color: #fafafa;
}

/* Header Styles */
.dashboard-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1.5rem 2.5rem;
    background-color: #ffffff;
    border-bottom: 1px solid #e9ecef;
}

.brand {
    display: flex;
    flex-direction: column;
}

.brand-title {
    font-size: 1.25rem;
    font-weight: 700;
    color: #111;
    margin-bottom: 0.25rem;
}

.brand-subtitle {
    font-size: 0.85rem;
    color: #6c757d;
}

.user-profile {
    display: flex;
    align-items: center;
    gap: 1.5rem;
}

.user-name {
    font-size: 0.95rem;
    color: #333;
}

.logout-link {
    font-size: 0.95rem;
    color: #0d6efd;
    text-decoration: none;
    font-weight: 500;
}

.logout-link:hover {
    text-decoration: underline;
}

/* Preview Mode Bar */
.preview-bar {
    display: flex;
    align-items: center;
    gap: 1.5rem;
    padding: 1rem 2.5rem;
    background-color: #fef3c7;
    border-bottom: 1px solid #fcd34d;
}

.preview-label {
    font-size: 0.95rem;
    font-weight: 600;
    color: #92400e;
}

.button-group {
    display: flex;
    gap: 0.75rem;
}

.preview-btn {
    padding: 0.5rem 1rem;
    background-color: #ffffff;
    border: 1px solid #ddd;
    border-radius: 4px;
    font-size: 0.85rem;
    color: #6c757d;
    cursor: pointer;
    transition: all 0.2s;
}

.preview-btn:hover {
    background-color: #f9fafb;
    border-color: #999;
}

.preview-btn.active {
    background-color: #fed7aa;
    color: #92400e;
    border-color: #fb923c;
    font-weight: 600;
}

/* Stepper Section */
.stepper-section {
    padding: 2rem 2.5rem;
    background-color: #ffffff;
    border-bottom: 1px solid #e9ecef;
}

.stepper-container {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    max-width: 1200px;
    margin: 0 auto;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    flex: 1;
}

.step-circle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background-color: #e9ecef;
    color: #6c757d;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    margin-bottom: 0.5rem;
    z-index: 2;
    font-size: 0.9rem;
}

.step-title {
    font-size: 0.8rem;
    color: #6c757d;
    text-align: center;
    margin-bottom: 0.25rem;
    font-weight: 500;
}

.step-status {
    font-size: 0.7rem;
    color: #999;
}

.step-line {
    position: absolute;
    top: 20px;
    left: 50%;
    right: -50%;
    height: 2px;
    background-color: #e9ecef;
    z-index: 1;
}

/* Completed step */
.step.completed .step-circle {
    background-color: #10b981;
    color: #ffffff;
}

.step.completed .step-title {
    color: #10b981;
    font-weight: 600;
}

.step.completed .step-status {
    color: #10b981;
}

.step.completed .step-line {
    background-color: #10b981;
}

/* Active step */
.step.active .step-circle {
    background-color: #f97316;
    color: #ffffff;
}

.step.active .step-title {
    color: #f97316;
    font-weight: 600;
}

.step.active .step-status {
    color: #f97316;
}

/* Alert Banner */
.alert-banner {
    display: flex;
    align-items: flex-start;
    gap: 1rem;
    padding: 1rem 2.5rem;
    background-color: #fed7aa;
    border-left: 4px solid #f97316;
    margin: 1.5rem 2.5rem;
    border-radius: 4px;
}

.alert-icon {
    font-size: 1.25rem;
    font-weight: bold;
    color: #f97316;
    flex-shrink: 0;
    width: 24px;
    height: 24px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.alert-content {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.alert-label {
    font-weight: 600;
    color: #b45309;
    font-size: 0.95rem;
}

.alert-message {
    color: #92400e;
    font-size: 0.9rem;
}

/* Feedback Section */
.feedback-section {
    padding: 2rem 2.5rem;
}

.feedback-card-container {
    max-width: 1200px;
    margin: 0 auto;
}

.feedback-card {
    background-color: #ffffff;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
    padding: 2rem;
    border-left: 4px solid #f97316;
}

.feedback-title {
    font-size: 1.1rem;
    font-weight: 600;
    color: #111;
    margin-bottom: 1.5rem;
}

.feedback-box {
    background-color: #fffbf0;
    border: 1px solid #fed7aa;
    border-radius: 6px;
    padding: 1.5rem;
    color: #333;
}

.feedback-box p {
    font-size: 0.95rem;
    line-height: 1.6;
    margin-bottom: 1rem;
    color: #5a5a5a;
}

.feedback-list {
    margin-left: 1.5rem;
    margin-bottom: 1.5rem;
    color: #5a5a5a;
}

.feedback-list li {
    font-size: 0.95rem;
    line-height: 1.6;
    margin-bottom: 0.75rem;
}

.feedback-instruction {
    font-size: 0.9rem;
    color: #666;
    font-style: italic;
}

/* Action Section */
.action-section {
    display: flex;
    justify-content: center;
    padding: 2rem 2.5rem;
    margin-bottom: 2rem;
}

.action-card {
    background-color: #ffffff;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
    padding: 3rem;
    text-align: center;
    max-width: 600px;
    width: 100%;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.action-icon {
    width: 60px;
    height: 60px;
    border-radius: 50%;
    background-color: #fed7aa;
    color: #f97316;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.75rem;
    margin-bottom: 1.5rem;
}

.action-title {
    font-size: 1.15rem;
    font-weight: 600;
    color: #111;
    margin-bottom: 0.5rem;
}

.action-subtitle {
    font-size: 0.9rem;
    color: #6c757d;
    margin-bottom: 2rem;
}

.action-button {
    background-color: #f97316;
    color: #ffffff;
    border: none;
    padding: 0.75rem 2rem;
    border-radius: 6px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.2s;
}

.action-button:hover {
    background-color: #ea580c;
}

.action-button:active {
    background-color: #dc2626;
}

/* Responsive Design */
@media (max-width: 768px) {
    .dashboard-header,
    .preview-bar,
    .stepper-section,
    .alert-banner,
    .feedback-section,
    .action-section {
        padding-left: 1rem;
        padding-right: 1rem;
    }

    .stepper-container {
        gap: 0.5rem;
    }

    .step {
        width: 70px;
    }

    .step-title {
        font-size: 0.7rem;
    }

    .preview-bar {
        flex-direction: column;
        align-items: flex-start;
        gap: 1rem;
    }

    .button-group {
        width: 100%;
        flex-wrap: wrap;
    }

    .feedback-card {
        padding: 1.5rem;
    }

    .action-card {
        padding: 1.5rem;
    }
}

